(391, 'Paket Nasi Ayam Rendang', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/96102937-af3f-4cf5-a86e-0453e8bfd20f_Go-Biz_20260401_215707.jpeg?auto=format', 'Ayam dibumbui dengan Bumbu rendang khas Minang yang sangat ciamik, dagingnya empuk ditambah nasi dengan kuah gulai, lalapan, sayur nangka dan sambal. Selalu ada kenikmatan disetiap suapan.', 26000, 1, 20),
(392, 'Paket Nasi Ayam Lado Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/31c13bcf-a52f-45fc-8517-50f66e3f8186_Go-Biz_20260401_211758.jpeg?auto=format', 'Ayam goreng dicambur cabe hijau semakin nikmat ditambah nasi lengkap dengan lalapan, sayur nangka, sambal disiriam kuah gulai yang semakin nikmat.', 26000, 1, 20),
(393, 'Paket Nasi Ayam Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/331a0f0d-4823-4189-8a79-d2afbb71c3c0_Go-Biz_20260401_211044.jpeg?auto=format', 'Ayam goreng dengan cabe merah ditambah nasi dengan siraman kuah gulai ditambah lalapan, sambal dan sayur nangka yang sangat maknyooosss.', 26000, 1, 20),
(394, 'Paket Nasi Ayam Gulai / Ayam Sayur', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/ee93c2a6-6c2f-494e-bd2c-d47d1d27e819_Go-Biz_20260401_225115.jpeg?auto=format', 'Nasi lengkap dengan ayam gulai lembut dan gurih santan khas Minang.', 26000, 1, 20),
(395, 'Paket Nasi Ayam Goreng Bumbu / Serundeng', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/dcacb165-687e-46e0-9539-a38ad434121b_Go-Biz_20260401_223823.jpeg?auto=format', 'Paket nasi putih komplit dengan lauk ayam goreng kemudian ditaburi bumbu/serundeng khas minang rasa nya gurih dan mantap.', 26000, 1, 20),
(396, 'Paket Nasi Ayam Pop', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/1e5e752c-7935-49be-93fe-d19836b9b4f1_Go-Biz_20260403_235819.jpeg?auto=format', 'Nasi hangat dipadukan ayam pop gurih, sambal khas padang, dan lalapan serta sayur nangka yang menggoda selera.', 26000, 1, 20),
(397, 'Paket Nasi Ikan Kembung Balado / Sambal Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/1edd2b4a-6a0a-4021-ac32-413c48f1b967_Go-Biz_20260401_210346.jpeg?auto=format', 'Ikan kembung digoreng garing, ditaburi sambal merah atau boleh juga dengan sambal hijau, lengkap dengan nasi+sayur nangka+lalapan+sambal.', 24000, 1, 20),
(398, 'Paket Nasi Ikan Tongkol Goreng Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/ae8f2234-b42f-4d78-aea5-90b849840206_Go-Biz_20260403_235851.jpeg?auto=format', 'Nasi hangat dengan ikan tongkol balado dengan sayuran komplit.', 20000, 1, 20),
(399, 'Paket Nasi Kepala Tongkol Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/b95e6e32-69fe-4169-89aa-285d29e4391b_Go-Biz_20260401_211648.jpeg?auto=format', 'Paket nasi komplit dengan kepala tongkol dan sambal balado merah yang menggoda.', 20000, 1, 20),
(400, 'Paket Nasi Ikan Nila Goreng', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/1800683c-bb3a-4194-a483-7365e42d2b3c_Go-Biz_20260401_223951.jpeg?auto=format', 'Nasi putih disajikan dengan ikan nila goreng garing dan sambal balado serta lalapan dan sayur nangka juga.', 20000, 1, 20),
(401, 'Paket Nasi Patin Goreng Lado Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/c9561226-f523-4926-8970-4cd790fb28cd_Go-Biz_20260401_210459.jpeg?auto=format', 'Nasi lengkap dengan ikan patin goreng dengan sambal hijau serta jangan lupa sayur nangka beserta lalapannya juga.', 20000, 1, 20),
(402, 'Paket Nasi Patin Goreng Lado Merah', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/1255cb81-8eb7-4908-8846-9fac068b8659_Go-Biz_20260402_234344.jpeg?auto=format', 'Nasi lengkap dengan ikan patin goreng dengan sambal merah serta jangan lupa sayur nangka beserta lalapannya juga.', 20000, 1, 20),
(403, 'Paket Nasi Lele Sambel Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/bccd316a-ff58-42cb-a54f-925659c635df_Go-Biz_20260402_234331.jpeg?auto=format', 'Nasi lembut disajikan dengan lele goreng garing dan sambal hijau serta jangan lupa lalapan dan sayur nangkanya juga.', 20000, 1, 20),
(404, 'Paket Nasi Gulai Ikan Tongkol', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/30a9a734-310d-4676-907a-a2dbbc3fe453_a7794325-95e0-492a-9785-f7ede3530f33_Go-Biz_20200104_111918.jpeg?auto=format', 'Paket nasi komplit dengan lauk gulai ikan tongkol yang gurih, serta kaya rempah khas minang yang mengunggah selera.', 20000, 1, 20),
(405, 'Paket Nasi Gulai Kepala Ikan Tongkol', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/e5b1e2f9-1387-4d07-9f26-59a459205a0b_Go-Biz_20241022_135423.jpeg?auto=format', 'Paket nasi komplit dengan lauk gulai kepala ikan tongkol yang gurih, serta kaya rempah khas minang yang mengunggah selera.', 20000, 1, 20),
(406, 'Paket Nasi Gulai Ikan Patin', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/c22e8ddc-02b5-400d-a16b-7a30a61cd8a5_Go-Biz_20240316_144300.jpeg?auto=format', 'Paket nasi komplit dengan lauk gulai ikan patin yang gurih, serta kaya rempah khas minang yang mengunggah selera.', 20000, 1, 20),
(407, 'Paket Nasi Rendang (Daging Sapi)', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/5cac92fb-dbc9-4a1c-8681-573218657c1f_Go-Biz_20260412_201053.jpeg?auto=format', 'Nasi lengkap dengan rendang sapi khas Minang, lalapan, sayur nangka, sambal hijau, dan kuah gulai. (Harga Promo)', 26000, 1, 20),
(408, 'Paket Nasi Gulai Cincang Sapi', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/2b91a106-601a-4ee4-9779-20e964afd3ca_Go-Biz_20260402_230153.jpeg?auto=format', 'Olahan gulai cincang sapi dimasak dengan bumbu gulai khas Minang kaya rempah, sehingga tidak bau amis dan wangi rempah rempah yang nikmat ditambah dengan nasi. lalapan, sambal, dan gulai nangka semakin nikmat disantap.', 26000, 1, 20),
(409, 'Paket Nasi Gulai Kikil (Kulit)', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/90adfd46-9eed-4846-a4fa-187791cce74a_Go-Biz_20240317_205306.jpeg?auto=format', 'Paket nasi putih dengan lauk gulai kikil kenyal dengan kuah rempah kaya rasa yang menggoda selera.', 31000, 1, 20),
(410, 'Paket Nasi Gulai Babat', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/ef6cf08c-c254-4073-a613-68f89eda2be1_Go-Biz_20250130_132815.jpeg?auto=format', 'Nasi putih disajikan dengan gulai babat kaya rempah, lalapan segar dan sambal serta sayur nangka yang menggoda selera.', 26000, 1, 20),
(411, 'Paket Nasi Asam Padeh Gajeboh', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/a3ea35d3-1e41-44c3-ae4b-bd4c1cf1b16a_Go-Food-Merchant_20251107_151636.jpeg?auto=format', 'Nasi asam padeh gajeboh pedas dan segar kaya rempah, lengkap dengan lalapan,sambal dan sayur nangka.', 26000, 1, 20),
(412, 'Paket Nasi Rendang Limpa', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/29d3432d-7f5c-4cd4-bf58-e600f8bb3a3e_Go-Food-Merchant_20250617_115727.jpeg?auto=format', 'Nasi lengkap dengan rendang limpa yang menggoda selera.', 28000, 1, 20),
(413, 'Paket Nasi Gulai Kalio Hati Sapi', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/67f1023a-5b61-426a-b239-7b19182ddd27_Go-Food-Merchant_20250617_115854.jpeg?auto=format', 'Paket nasi komplit disajikan dengan gulai kalio hati sapi yang kaya rempah.', 26000, 1, 20),
(414, 'Paket Nasi Dendeng Batokok Lado Merah', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/c9b6abcd-9687-4585-b53a-37e032346298_Go-Biz_20240114_120808.jpeg?auto=format', 'Paket nasi komplit dengan lauk dendeng batokok lado merah yang menggoda selera.', 29000, 1, 20),
(415, 'Paket Nasi Udang Cabe Merah', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/4844c188-9de2-48a0-ad05-98ae3a5c3dd4_Go-Biz_20260402_234317.jpeg?auto=format', 'Udang Laut digoreng gurih dicambur cabe merah, disantap dengan nasi lengkap lalapan sayur nangka dan disiram kuah mantap buat pembangkit selera.', 26000, 1, 20),
(416, 'Paket Nasi Paru Goreng', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/3597a8d3-d94f-490d-a38c-419be8a9c4f9_Go-Biz_20260401_220128.jpeg?auto=format', 'Paket nasi komplit dengan lauk paru goreng yang menggoda selera.', 28000, 1, 20),
(417, 'Paket Nasi Ikan Salam Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/eb1f5f0b-345a-40c9-827b-717570837bb0_1120c7cc-0da1-4fe9-a00a-c0dcd36d2bf5_Go-Biz_20190705_190544.jpeg?auto=format', 'Sajian ikan salam yang di goreng kemudian dicampur cabe merah dipadukan dengan nasi lengkap dengan lalapan, sayur nangka, sambal merah, disiram kuah gulai yang menambah kegurihan dalam setiap suapan nya.', 24000, 1, 20),
(418, 'Paket Nasi Ikan Mas Goreng', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/52fbd324-d8fb-41f0-99c7-ea3cef7c73f3_Go-Food-Merchant_20250817_112325.jpeg?auto=format', 'Paket nasi komplit dipadukan dengan ikan mas goreng renyah dan segar.', 20000, 1, 20),
(419, 'Paket Nasi Gulai Kepala Kakap', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/cdb3795f-0d7d-4253-aab9-bfff096d0e70_Go-Food-Merchant_20260412_201610.jpeg?auto=format', 'Paket Nasi Lengkap Dengan Lauk Gulai Kepala Kakap Yang Menggoda Selera.', 35000, 1, 20),
(420, 'Paket Nasi Asam Padeh Tongkol', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/768c88d5-fa5c-483c-84f7-190fb1f22b55_Go-Biz_20260402_230359.jpeg?auto=format', 'Paket nasi komplit dengan lauk asam pedas tongkol khas minang yang mengunggah selera.', 20000, 1, 20),
(421, 'Paket Nasi Asam Padeh Kepala Tongkol', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/a85dec49-72f6-4dfa-bf99-7fa1fadb5ecc_Go-Biz_20260401_225706.jpeg?auto=format', 'Paket nasi komplit dengan lauk asam pedas kepala tongkol khas minang yang mengunggah selera.', 20000, 1, 20),
(422, 'Paket Nasi Asam Padeh Ikan Patin', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/d8b168d6-a510-4ea1-a7b3-0d3364c81392_Go-Biz_20260401_225521.jpeg?auto=format', 'Paket nasi komplit dengan lauk asam pedas ikan patin khas minang yang mengunggah selera.', 20000, 1, 20),
(423, 'Paket Nasi Pindang Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/0e5748b0-b1ed-4e06-9889-0e4fc87214b6_Go-Biz_20260407_220211.jpeg?auto=format', 'Pindang digoreng dibumbu cabe merah yang nikmat dan gurih ditambah nasi lengkap dengan lalapan, sayur nangka, sambal, disiram dengan kuah gulai semakin nikmat untuk memanjakan lidah.', 19000, 1, 20),
(424, 'Paket Nasi Telur Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/3e98a117-33ae-41c3-bae7-ada4aa0fbfc6_Go-Biz_20260401_224054.jpeg?auto=format', 'Telur digoreng dibumbui cabe merah dipadukan nasi lengkap lalapan, sayur nangka, sambal, dan disiram kuah gulai yang semakin nikmat dan harga pas dikantong.', 19000, 1, 20),
(425, 'Paket Nasi Gulai Telor', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/4f5893ed-68ab-4e5c-b3d5-d5877c7a66b9_Go-Biz_20260412_201845.jpeg?auto=format', 'Telur bulat yang digulai dipadukan nasi lengkap lalapan, sayur nangka, sambal, dan disiram kuah gulai yang semakin nikmat dan harga pas dikantong.', 19000, 1, 20),
(426, 'Paket Nasi Perkedel Kentang + Tahu Tempe', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/18be668a-8fc9-4cf8-861d-d8620b9bed24_Go-Biz_20260402_234300.jpeg?auto=format', 'Paket nasi komplit dengan lauk satu perkedel kentang dan satu tahu tempe yang menggugah selera.', 19000, 1, 20),
(427, 'Paket Nasi Tahu Tempe', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/1036ec6c-ab3b-4058-8033-39a09e129058_Go-Biz_20260401_224837.jpeg?auto=format', 'Paket nasi komplit dengan lauk dua tahu, dua tempe yang menggoda selera.', 19000, 1, 20),
(428, 'Paket Nasi Ati Ampela Goreng Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/24452319-b8b2-41d5-8236-b26839db0b4b_Go-Biz_20260401_224425.jpeg?auto=format', 'Paket nasi putih komplit disajikan dengan ati ampela goreng lado merah yang menggoda.', 19000, 1, 20),
(429, 'Paket Nasi Asin Tempe Cabe Merah', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/bd23d86f-97e8-4c81-be4e-69bc8bc348ac_e701f32d-1beb-4bc5-862c-d2784c79ef70_Go-Biz_20190702_095717.jpeg?auto=format', 'Sajian Asin + tempe digoreng dengan sambel cabe merah dipadukan nasi dan lalapan disiram kuah gulai membuat gurih disetiap suapannya.', 19000, 1, 20),
(430, 'Paket Nasi Telor Dadar', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/a2a9fbdd-d5c8-427e-8d24-45e66c33d28f_Go-Biz_20260402_234239.jpeg?auto=format', 'Paket nasi putih komplit dengan lauk telor dadar yang menggoda selera.', 19000, 1, 20),
(431, 'Paket Nasi Rendang Telor', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/7983ea47-18ed-434b-bca8-3eadf69c1095_Go-Food-Merchant_20260401_213236.jpeg?auto=format', 'Paket nasi lengkap dengan rendang telur lembut, cita rasa kaya rempah khas Minang dan menggoda untuk disantap.', 19000, 1, 20),
(432, 'Paket Nasi Ikan Bilis Kering/maco Bilis', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/3cc2ebeb-27f9-403b-8230-6875475472fc_Go-Biz_20230325_150932.jpeg?auto=format', 'Paket Nasi Putih Komplit Dengan Lauk IIkan Bilis Kering/maco Bilis Digoreng Garing Kemudian Disambal Hijau.rasanya Mantap...', 19000, 1, 20),
(433, 'Paket Nasi Teri Goreng Petay', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/35487fa0-29e4-4a7d-a4f3-fe141e19c786_Go-Biz_20260401_224539.jpeg?auto=format', 'Nasi teri goreng petay lengkap dengan sambal, lalapan serta sayur nangka juga.', 19000, 1, 20),
(434, 'Paket Nasi Teri Goreng Kacang Dan Tempe', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/d2d66704-01d3-40d1-b3d8-1da74b7a3648_Go-Biz_20230522_111358.jpeg?auto=format', 'Nasi teri goreng kacang tempe lengkap dengan sambal, lalapan serta sayur nangka juga.', 19000, 1, 20),
(435, 'Paket Nasi Taruang Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/f0fd1a56-f8d1-4bf5-a007-a0c8a5fc25fe_Go-Biz_20260401_224318.jpeg?auto=format', 'Nasi lengkap dengan terong balado yang menggoda.', 19000, 1, 20),
(436, 'Paket Nasi Jengkol Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/5a275cdd-0903-41cd-94e8-46d8aaba5e18_Go-Biz_20220823_154114.jpeg?auto=format', 'Paket nasi komplit dengan lauk jengkol balado yang menggoda selera.', 19000, 1, 20),
(437, 'Gulai Tunjang Kaki Sapi (Kikil)', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/385d6af1-38c5-41d9-be11-a460cc817c64_Go-Biz_20260402_234923.jpeg?auto=format', 'Gulai tunjang sapi khas Minang, rempah gurih dan daging lembut.', 30000, 1, 20),
(438, 'Dendeng Batokok Lado Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/b85147f2-5f21-4300-aa0b-6d05f40db0a4_Go-Biz_20260402_234847.jpeg?auto=format', 'Dendeng batokok ditambah dengan lado khas Minang.', 22000, 1, 20),
(439, 'Cumi Goreng Lado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/99e22574-4327-4699-9667-49611457a92d_Go-Biz_20260402_234948.jpeg?auto=format', 'Cumi goreng dicampur potongan cabe dan tomat sehingga rasanya yang asin, pedas, segar, yang meningkatkan selera makan.', 18000, 1, 20),
(440, 'Ayam Rendang', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/ca8d76c0-9667-46d6-867d-6b297cb7dfc4_Go-Biz_20260402_234909.jpeg?auto=format', 'Ayam yang dimasak dengan bumbu rendang khas Minang, sangat nikmat apalagi dimakan dengan nasi disantap dengan keluarga, pasangan atau sendiri. Membuat perut kenyang dan berkah.', 18000, 1, 20),
(441, 'Ayam Lado Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/3296fcea-7843-468b-a996-3788bccd6ee2_Go-Biz_20260402_234512.jpeg?auto=format', 'Ayam goreng (Paha dan Dada) dibumbui cabe hijau digoreng, rasanya gurih dan pedas membuat selera makan bertambah.', 18000, 1, 20),
(442, 'Ayam Gulai', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/673c139b-4330-433f-b47d-435d70c23931_Go-Biz_20260402_234936.jpeg?auto=format', 'Ayam Gulai khas minang yang enak dan lembut serta gurih santan nikmat untuk disantap.', 18000, 1, 20),
(443, 'Ayam Goreng Bumbu / Serundeng', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/f4ef1876-dae0-49a5-b780-86ab1b76a1b4_Go-Biz_20260402_234818.jpeg?auto=format', 'Ayam goreng bumbu atau bisa disebut ayam serundeng yang mengunggah selera.', 18000, 1, 20),
(444, 'Ayam Goreng Balado', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/3e3b151a-a396-4492-b994-358ca6eee23f_Go-Biz_20260402_234553.jpeg?auto=format', 'Ayam goreng dengan bumbu cabe merah yang segar sehingga nikmat dimakan dengan nasi.', 18000, 1, 20),
(445, 'Ayam Pop', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/6fa2ab78-15cf-4214-958d-6e67f12f06f6_Go-Biz_20260403_235913.jpeg?auto=format', 'Ayam pop dan sambal khas padang yg mengunggah selera.', 18000, 1, 20),
(446, 'Ikan Kembung Balado / Sambal Hijau', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/caf491b8-2e8d-4025-b753-d55e9492790f_Go-Biz_20260402_234525.jpeg?auto=format', 'Ikan kembung yang digoreng lalu dicampuri sambal merah maupun sambal hijau yang menggugah selera (boleh request mau dicampur sambal merah atau sambal hijau).', 17000, 1, 20),
