(892, 'Es Teler Sultan', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/23faf392-f8a4-4f05-abd2-2b7bbbc08c4e_Go-Biz_20260309_002944.jpeg?auto=format', 'Es Teler Creamy, alpukat + nangka + Jelly Blueberry - cincau + Jelly kelapa + Agar2 Strawberry + kuah Creamy Authentic AI Drinks', 23000, 3, 31),
(893, 'MANGO Sago Super Creamy!', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/577eb1db-21c7-4913-9c4c-836adcd6d12b_Go-Biz_20260309_003045.jpeg?auto=format', 'Dessert Populer Di Asian, Potongan Buah Mangga Yg Fresh Dan Yummy, Berpadu Dengan Kuah Creamy Yang Lezat. MANGO Sago Kaya Rasa, Sagu Mutiara + Bijih Selasih + Jelly Mangga + Daun Mint', 23000, 3, 31),
(894, 'Es Teler Tokyo', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/32a0cfb2-3e64-451b-acc3-f33571a08c20_Go-Biz_20250825_222917.jpeg?auto=format', 'Signature Es Teler A.I. Drinks, Dengan Sensasi Popping Boba Strawberry Yg Meletus Di Mulut, Taburan Keju, Isian Alpukat + Jelly kelapa + Jelly Strawberry + kuah Creamy Authentic AI Drinks', 23000, 3, 31),
(895, 'Buko Pandan Filipino', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/565d7efc-de84-4974-9a8a-8431a70bb8f0_Go-Biz_20250810_231538.jpeg?auto=format', 'Dessert khas negara Philipines, dengan isian: nata de coco + agar2 Ijo + nikmat dengan parutan keju dan saus creamy authentic khas ai drinks', 23000, 3, 31),
(896, 'Es Teler Teko', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/8fac5015-ba40-4824-abc9-ca05dfffcfca_Go-Food-Merchant_20260108_223215.jpeg?auto=format', 'Es teler teko avengers! Dengan topping lengkap semua ada: jelly cincau, kelapa, melon, stroberi, kuah creamy terkental. Alpukat, nangka, selasih, keju melimpah. +Free teko ukuran 1000 ml', 45000, 3, 31),
(897, 'Iced Dubai Pistachio Coffee', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/eb610c7b-7d5f-4d42-822e-de0aee652ea7_Go-Food-Merchant_20260120_191945.jpeg?auto=format', 'Sauce Pistachio + Susu Uht + Espresso + Pistachio Nut Crumbs', 19000, 3, 31),
(898, 'Butterscotch Sea Salt Latte', 'https://i.gojekapi.com/darkroom/gofood-indonesia/v2/images/uploads/8f7620ae-16f5-427b-bfbb-eedc406c0196_Go-Food-Merchant_20260120_192103.jpeg?auto=format', 'Butterscotch Syrup + Susu Uht + Espresso + Creamer + Sea Salt + Cookie Crumbs', 19000, 3, 31),
(899, 'Matcha Creamy Latte', '', 'Minuman susu dengan teh hijau (matcha) Jepang ala AI Drinks yang kental', 15000, 3, 31),
(900, 'Es Kopi Susu Gula Aren', '', 'Perpaduan espresso, susu segar, dan manisnya gula aren asli', 15000, 3, 31),
